WorkflowProcessEvent.eventDescription:
var ADICIONAR_TAREFAS = 4;
var EXECUTAR_ATIVIDADES = 18;
var FEITO = 5;
var FIM = 7;

var PROCESS_ATIVIDADES = 'gestaodetarefas';

function afterProcessFinish(processId) {
	// data termino
	var data_transtermino = new Date();
	log.info("Data termino: " + hAPI.getCardValue("date_terminoatividade"));
	var arrdatatermino = hAPI.getCardValue("date_terminoatividade").split("/");
	var mestermino = arrdatatermino[1];
	var diatermino = arrdatatermino[0];
	var anotermino = arrdatatermino[2];

	data_transtermino.setDate(diatermino);
	data_transtermino.setMonth(parseInt(mestermino - 1));
	data_transtermino.setFullYear(anotermino);
	data_transtermino.setHours(0, 0, 0, 0, 0);
	log.info("Datatrans termino: " + data_transtermino);

	// data finalizada
	var data_transfinal = new Date();
	log.info("Data finalizada: " + hAPI.getCardValue("data_finalizacao"));
	var arrdatafinal = hAPI.getCardValue("data_finalizacao").split("-");
	var mesfinal = arrdatafinal[1];
	var diafinal = arrdatafinal[2];
	var anofinal = arrdatafinal[0];

	data_transfinal.setDate(diafinal);
	data_transfinal.setMonth(parseInt(mesfinal - 1));
	data_transfinal.setFullYear(anofinal);
	data_transfinal.setHours(0, 0, 0, 0, 0);
	log.info("Datatrans final: " + data_transfinal);

	if (data_transfinal <= data_transtermino) {

		hAPI.setCardValue("txt_pontuacao", parseFloat(hAPI
				.getCardValue("txt_pontuacaoprioridade")
				* hAPI.getCardValue("txt_noprazo") / 100));
		log.info("Pontuacao alcanda: " + hAPI.getCardValue("txt_pontuacao"));

	} else {
		hAPI.setCardValue("txt_pontuacao", parseFloat(hAPI
				.getCardValue("txt_pontuacaoprioridade")
				* hAPI.getCardValue("txt_foraprazo") / 100));
		log.info("Pontuacao alcanda: " + hAPI.getCardValue("txt_pontuacao"));

	}
}

function onNotify(subject, receivers, template, params) {
	
	var ATIVIDADE = hAPI.getCardValue('txt_descatividade');
	var PRAZO     = hAPI.getCardValue('date_terminoatividade');
    var msg       = "Tarefa - "+ ATIVIDADE +" até "+ PRAZO;
	
	// BUSCAR DADOS DA TABELA PAI-FILHA ONDE ESTÃO LANÇADAS AS MOVIMENTAÇÕES DO COLABORADOR
    var numProcess = getValue("WKNumProces");
    
    // Busca a Lista com o número da solicitação dos filhos
    var childrenProcess = hAPI.getChildrenInstances(numProcess);
 
    // Busca os dados do formulário da solicitação filha
    var childCardData = hAPI.getCardData(childrenProcess.get(childrenProcess.size()));
 
    // Replica um dado do formulário da solicitação filha para o formulário da solicitação pai
    var my_date  = childCardData.get("date_Status");
    var my_Espec = childCardData.get("txtEspecificacao");
    
    // SE TEM MSG NO ULTIMO MOVIMENTO ADICIONA EM SUBJECT
    if (my_Espec !=null) {
    	msg = msg +(" em "+my_date+" obs "+my_espec);
    }
    
    // SUBJECT
	subject.add( msg );	
}

function beforeSendData(customFields, customFacts) {
	customFields[0]  = hAPI.getCardValue( "txt_projeto" );
	customFields[2]  = hAPI.getCardValue( "txt_descatividade" );
	customFields[4]  = hAPI.getCardValue( "txt_areaprojeto" );
	customFields[6]  = hAPI.getCardValue( "txt_nomeresponsavel" );
	customFields[7]  = hAPI.getCardValue( "txt_descpriorid" );
	customFields[8]  = hAPI.getCardValue( "txt_pontuacao_dis" );
	customFields[9]  = hAPI.getCardValue( "txt_pontuacao" );
	customFields[10] = hAPI.getCardValue( "date_inicioatividade" );
	customFields[11] = hAPI.getCardValue( "date_terminoatividade" );
	customFields[12] = hAPI.getCardValue( "date_reprogramacao" );
	customFields[13] = hAPI.getCardValue( "data_finalizacao" );

}

function beforeStateEntry(sequenceId) {
	var cardData = new java.util.HashMap();

	var userList = new java.util.ArrayList();
	userList.add(getValue("WKUser"));

	// GERAR TAREFAS
	if (sequenceId == EXECUTAR_ATIVIDADES || sequenceId == FEITO) {


		// criarAtividades(hAPI);

		reprogramacaoDeFinalizacao();

	}
}

